before_code:
module counter_16bit(
    input clk,
    input rst,
    input [15:0] load_val,
    input load_en,
    output [15:0] count_out
);
    always @(posedge clk or posedge rst)
        if (rst) count_out <= 0;
        else if (load_en) count_out <= load_val;
        else count_out <= count_out + 1;
endmodule

module top();
    logic clk, rst, load_en;
    logic [15:0] load_data, counter_output;
    counter_16bit inst(
        .load_value(load_data),
        .load_en(load_en),
        .count_out(counter_output),
        .clk(clk),
        .rst(rst)
    );
endmodule

